import React from "react";
import { NAV_LINKS } from "../data/siteData";

/**
 * Header — frosted glass floating navbar.
 * Props:
 *   ready      {boolean} — whether the app has finished loading (controls fade-in)
 *   onMenuOpen {function} — open the slide menu
 */
const Header = ({ ready, onMenuOpen }) => {
  return (
    <header
      className="header-shimmer"
      style={{
        position: "fixed",
        top: "24px",
        left: "50%",
        transform: "translateX(-50%)",
        width: "94%",
        height: "92px",
        zIndex: 5000,
        display: "grid",
        gridTemplateColumns: "auto 1fr auto",
        alignItems: "center",
        padding: "0 36px",
        borderRadius: "30px",
        background: "rgba(0,0,0,.38)",
        backdropFilter: "blur(18px)",
        border: "1px solid rgba(255,255,255,.08)",
        overflow: "hidden",
        opacity: ready ? 1 : 0,
        transition: "opacity 1.8s cubic-bezier(.19,1,.22,1)",
        transitionDelay: ready ? "1.8s" : "0s",
      }}
    >
      {/* ── LEFT: RSD Signature ── */}
      <div
        className="flex items-center"
        style={{
          opacity: ready ? 1 : 0,
          animation: ready ? "slideInLeft 2s cubic-bezier(.19,1,.22,1) forwards" : "none",
          animationDelay: "2.1s",
        }}
      >
        <div
          className="flex items-center"
          style={{
            fontFamily: "'Plus Jakarta Sans', sans-serif",
            fontWeight: 800,
            textTransform: "uppercase",
            letterSpacing: "-2px",
            lineHeight: 1,
          }}
        >
          {["R", "S", "D"].map((letter, i) => (
            <span
              key={letter}
              className="rsd-letter"
              style={{
                fontSize: "clamp(34px, 5vw, 62px)",
                marginLeft: i > 0 ? "-10px" : "0",
              }}
            >
              {letter}
            </span>
          ))}
        </div>
      </div>

      {/* ── CENTER: Brand Name ── */}
      <div className="text-center">
        <a
          href="#"
          style={{
            color: "#fff",
            textDecoration: "none",
            fontFamily: "'Tenor Sans', serif",
            fontSize: "clamp(15px, 2vw, 28px)",
            letterSpacing: "10px",
            textTransform: "uppercase",
          }}
        >
          Rakesh Sharma Design
        </a>
      </div>

      {/* ── RIGHT: Menu Trigger ── */}
      <div className="flex justify-end">
        <button
          onClick={onMenuOpen}
          aria-label="Open Menu"
          style={{
            width: "62px",
            height: "62px",
            borderRadius: "50%",
            border: "1px solid rgba(255,255,255,.12)",
            background: "rgba(255,255,255,.05)",
            cursor: "pointer",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            position: "relative",
            overflow: "hidden",
            transition: "transform .8s cubic-bezier(.19,1,.22,1)",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = "rotate(90deg) scale(1.04)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = "rotate(0deg) scale(1)";
          }}
        >
          <div className="flex flex-col gap-[5px] z-10">
            <span
              style={{ width: "22px", height: "1px", background: "#fff", display: "block" }}
            />
            <span
              style={{ width: "22px", height: "1px", background: "#fff", display: "block" }}
            />
          </div>
        </button>
      </div>
    </header>
  );
};

export default Header;
